void sobel_filtering( )
     /* Spatial filtering of image data */
     /* Sobel filter (horizontal differentiation */
     /* Input: image1[y][x] ---- Outout: image2[y][x] */
{
  /*Knob Variables Declaration Start*/
  int downsample_factor = 1;
  int segment_pattern = 0;
  int early_exit_enabled = 0;
  int early_exit_threshold = 100;
  /*Knob Variables Declaration End*/

  /* Definition of Sobel filter in horizontal direction */
  int weight[3][3] = {{ -1,  0,  1 },
                      { -2,  0,  2 },
                      { -1,  0,  1 }};
  double pixel_value;
  double min, max;
  int x, y, i, j;  /* Loop variable */

  min = DBL_MAX;
  max = -DBL_MAX;
  int processed_pixels = 0;
  int min_samples = 50;

  /* @Approximation applied [No.22] [Spatial Downsampling] */
  /* @Approximation applied [No.21] [Early-Exit Approximation] */
  for (y = 1; y < y_size1 - 1; y += downsample_factor) {
    for (x = 1; x < x_size1 - 1; x += downsample_factor) {
      pixel_value = 0.0;

      /* @Approximation applied [No.30] [Pattern Segmentation] */
      if (segment_pattern == 0) {
        /* Full 3x3 convolution */
        for (j = -1; j <= 1; j++) {
          for (i = -1; i <= 1; i++) {
            pixel_value += weight[j + 1][i + 1] * (image1[y + j][x + i]);
          }
        }
      } else if (segment_pattern == 1) {
        /* Cross pattern: center column + center row */
        for (i = -1; i <= 1; i++) {
          pixel_value += weight[1][i + 1] * (image1[y][x + i]);     /* center row */
          if (i != 0) {
            pixel_value += weight[i + 1][1] * (image1[y + i][x]);   /* center column excluding center */
          }
        }
      } else if (segment_pattern == 2) {
        /* Center column only */
        for (j = -1; j <= 1; j++) {
          pixel_value += weight[j + 1][1] * (image1[y + j][x]);
        }
      }

      if (pixel_value < min) min = pixel_value;
      if (pixel_value > max) max = pixel_value;
      processed_pixels++;

      /* Early exit when range stabilizes */
      if (early_exit_enabled && processed_pixels > min_samples && 
          (max - min) > early_exit_threshold) {
        goto pass1_complete;
      }
    }
  }

  pass1_complete:
  if ((int)(max - min) == 0) {
    return;
  }

  /* New loop variables */
  int xa;
  int ya;
  /* New pixel_value */
  double pixel_value_app;
  /* Initialization of image2[y][x] */
  x_size2 = x_size1;
  y_size2 = y_size1;
  for (ya = 0; (ya < y_size2); ya++) {
    for (xa = 0; (xa < x_size2); xa++) {
      image2[ya][xa] = 0;
    }
  }

  /* Generation of image2 after linear transformtion */
  /* @Approximation applied [No.22] [Spatial Downsampling] */
  for (ya = 1; (ya < y_size1 - 1); ya += downsample_factor) {
    for (xa = 1; (xa < x_size1 - 1); xa += downsample_factor) {
      pixel_value_app = 0.0;

      /* @Approximation applied [No.30] [Pattern Segmentation] */
      if (segment_pattern == 0) {
        /* Full 3x3 convolution */
        for (j = -1; j <= 1; j++) {
          for (i = -1; i <= 1; i++) {
            pixel_value_app += weight[j + 1][i + 1] * image1[ya + j][xa + i];
          }
        }
      } else if (segment_pattern == 1) {
        /* Cross pattern: center column + center row */
        for (i = -1; i <= 1; i++) {
          pixel_value_app += weight[1][i + 1] * (image1[ya][xa + i]);     /* center row */
          if (i != 0) {
            pixel_value_app += weight[i + 1][1] * (image1[ya + i][xa]);   /* center column excluding center */
          }
        }
      } else if (segment_pattern == 2) {
        /* Center column only */
        for (j = -1; j <= 1; j++) {
          pixel_value_app += weight[j + 1][1] * (image1[ya + j][xa]);
        }
      }

      pixel_value_app = MAX_BRIGHTNESS * (pixel_value_app - min) / (max - min);
      unsigned char computed_value = (unsigned char)pixel_value_app;

      /* Fill the downsampled block with the computed value */
      for (int fy = 0; fy < downsample_factor && (ya + fy) < y_size1 - 1; fy++) {
        for (int fx = 0; fx < downsample_factor && (xa + fx) < x_size1 - 1; fx++) {
          image2[ya + fy][xa + fx] = computed_value;
        }
      }
    }
  }
}
